import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate  = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(email, password);
      navigate('/dashboard');
    } catch (e: any) {
      setError(e.response?.data?.message || 'Invalid email or password.');
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight:'100vh', display:'grid', gridTemplateColumns:'1fr 1fr', background:'#fafafa' }}>

      {/* ─── Left: Form ─── */}
      <div style={{ display:'flex', flexDirection:'column', padding:'40px 56px' }}>

        {/* Top brand */}
        <div style={{ display:'flex', alignItems:'center', gap:10 }}>
          <div style={{
            width:32, height:32, borderRadius:8,
            background:'#18181b', color:'#fff',
            display:'flex', alignItems:'center', justifyContent:'center',
            fontWeight:700, fontSize:15, letterSpacing:'-0.5px'
          }}>L</div>
          <div style={{ fontSize:15, fontWeight:600, color:'#18181b', letterSpacing:'-0.2px' }}>
            LibraryMS
          </div>
        </div>

        {/* Center form */}
        <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center', padding:'24px 0' }}>
          <div style={{ width:'100%', maxWidth:380 }} className="page-enter">

            <h1 style={{ fontSize:28, fontWeight:700, color:'#18181b', letterSpacing:'-0.6px', marginBottom:6 }}>
              Sign in to your account
            </h1>
            <p style={{ fontSize:14, color:'#71717a', marginBottom:30 }}>
              Welcome back. Enter your credentials to continue.
            </p>

            {error && (
              <div role="alert" style={{
                background:'#fef2f2', border:'1px solid #fecaca', color:'#991b1b',
                padding:'10px 12px', borderRadius:8, fontSize:13, marginBottom:18,
                display:'flex', alignItems:'flex-start', gap:8
              }}>
                <span style={{ width:6, height:6, borderRadius:'50%', background:'#dc2626', marginTop:6, flexShrink:0 }}/>
                <span>{error}</span>
              </div>
            )}

            <form onSubmit={handleSubmit} noValidate>
              <div style={{ marginBottom:16 }}>
                <label htmlFor="email" className="label">Email</label>
                <input id="email" className="field" type="email" autoComplete="email" required
                  value={email} onChange={e=>setEmail(e.target.value.toLowerCase())}
                  placeholder="you@example.com" />
              </div>

              <div style={{ marginBottom:22 }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'baseline', marginBottom:6 }}>
                  <label htmlFor="password" className="label" style={{ marginBottom:0 }}>Password</label>
                  <Link to="/forgot-password" style={{
                    fontSize:12.5, color:'#2563eb', textDecoration:'none', fontWeight:500
                  }}>Forgot password?</Link>
                </div>
                <div style={{ position:'relative' }}>
                  <input id="password" className="field" type={showPass?'text':'password'} autoComplete="current-password" required
                    value={password} onChange={e=>setPassword(e.target.value)}
                    placeholder="Enter your password" style={{ paddingRight:64 }} />
                  <button type="button" onClick={()=>setShowPass(v=>!v)}
                    style={{
                      position:'absolute', right:8, top:'50%', transform:'translateY(-50%)',
                      background:'transparent', border:'none', color:'#71717a',
                      fontSize:12, fontWeight:500, padding:'4px 8px', borderRadius:4
                    }}>
                    {showPass?'Hide':'Show'}
                  </button>
                </div>
              </div>

              <button type="submit" disabled={loading} className="btn btn-primary btn-lg"
                style={{ width:'100%' }}>
                {loading ? 'Signing in…' : 'Sign in'}
              </button>
            </form>

            <p style={{ textAlign:'center', fontSize:13.5, color:'#71717a', marginTop:24 }}>
              New student or staff?{' '}
              <Link to="/register" style={{ color:'#18181b', fontWeight:600, textDecoration:'none' }}>
                Create an account
              </Link>
            </p>
          </div>
        </div>

        {/* Footer */}
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', fontSize:12, color:'#a1a1aa' }}>
          <span>© {new Date().getFullYear()} BAUST Library</span>
          <span>Library Management System</span>
        </div>
      </div>

      {/* ─── Right: Brand panel ─── */}
      <div style={{
        background:'#0a0a0a',
        color:'#fafafa',
        display:'flex', flexDirection:'column', justifyContent:'space-between',
        padding:'48px 56px', position:'relative', overflow:'hidden'
      }}>
        {/* Subtle grid backdrop */}
        <div style={{
          position:'absolute', inset:0,
          backgroundImage:'linear-gradient(rgba(255,255,255,0.04) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.04) 1px, transparent 1px)',
          backgroundSize:'48px 48px',
          maskImage:'radial-gradient(ellipse at 50% 30%, #000 30%, transparent 80%)',
          WebkitMaskImage:'radial-gradient(ellipse at 50% 30%, #000 30%, transparent 80%)',
          pointerEvents:'none'
        }}/>

        <div style={{ position:'relative' }}>
          <p className="eyebrow" style={{ color:'#71717a', marginBottom:14 }}>BAUST</p>
          <p style={{ fontSize:13, color:'#a1a1aa', maxWidth:340, lineHeight:1.6 }}>
            Bangladesh Army University of Science and Technology
          </p>
        </div>

        <div style={{ position:'relative', maxWidth:480 }}>
          <h2 style={{ fontSize:38, fontWeight:700, lineHeight:1.15, letterSpacing:'-1px', color:'#fafafa', marginBottom:16 }}>
            A modern library, designed for students &amp; staff.
          </h2>
          <p style={{ fontSize:15, color:'#a1a1aa', lineHeight:1.6 }}>
            Browse the catalogue, request books, track borrows, and stay up to
            date with announcements — all in one place.
          </p>

          <div style={{ display:'flex', gap:32, marginTop:40 }}>
            <Stat label="Books in catalogue" value="10,000+" />
            <Stat label="Active members"     value="2,400+"  />
            <Stat label="Avg. response"      value="< 24h"   />
          </div>
        </div>

        <div style={{ position:'relative', display:'flex', gap:18, fontSize:12, color:'#52525b' }}>
          <span>Privacy</span>
          <span>Terms</span>
          <span>Help</span>
        </div>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <div style={{ fontSize:22, fontWeight:700, color:'#fafafa', letterSpacing:'-0.5px' }}>{value}</div>
      <div style={{ fontSize:12, color:'#71717a', marginTop:2 }}>{label}</div>
    </div>
  );
}
